def ceil_search(arr, low, high, x):
  """
  Searches for the ceiling of a value x in a sorted array arr.
  The ceiling is the smallest element in the array greater than or equal to x.
  This function returns the index of the ceiling element.
  Args:
      arr: The sorted list of numbers.
      low: The starting index of the search range.
      high: The ending index of the search range.
      x: The number to find the ceiling for.
  Returns:
      The index of the ceiling of x, or -1 if no ceiling exists.
  """
  # Base cases
  if x <= arr[low]:
    return low
  if x > arr[high]:
    return -1
  mid = (low + high) // 2
  if arr[mid] == x:
    return mid
  elif arr[mid] < x:
    if mid + 1 <= high and x <= arr[mid + 1]:
      return mid + 1
    else:
      return ceil_search(arr, mid + 1, high, x)
  else:  # arr[mid] > x
    if mid - 1 >= low and x > arr[mid - 1]:
      return mid
    else:
      return ceil_search(arr, low, mid - 1, x)

