    # for (int i = 1; i < n; i++)
    for i in range(1, n):
        # for (int j = i; j <= n; j++)
        for j in range(i, n + 1):
            # table[j] += table[j - i];
            table[j] += table[j - i]
    # return table[n];
    return table[n]

