def is_power_of_two(n: int) -> bool:
  if n == 0:
    return False
  while n != 1:
    if n % 2 != 0:
      return False
    # In C++, dividing two integers results in an integer (truncation).
    # In Python, we use // for integer division.
    n = n // 2
  return True
